import{_ as a,o as t,c as r,ag as s}from"./chunks/framework.ETe_P6d1.js";const o="/kaiping-reports/assets/1.CR1uh-pe.png",m="/kaiping-reports/assets/2.BsCQIsRP.png",n="/kaiping-reports/assets/3.DF6CI-F5.png",i="/kaiping-reports/assets/4.B2rqauei.png",p="/kaiping-reports/assets/5.RXttQJYL.png",h="/kaiping-reports/assets/6.DZvJjfWt.png",l="/kaiping-reports/assets/7.BMWtitpO.png",_="/kaiping-reports/assets/8.AOghORtX.png",g="/kaiping-reports/assets/9.LdLLoZHx.png",c="/kaiping-reports/assets/10.CdAn6pHh.png",d="/kaiping-reports/assets/11.BozbwdZ5.png",u="/kaiping-reports/assets/12.BvMGlZE-.png",b="/kaiping-reports/assets/13.BdAYLWDi.png",q="/kaiping-reports/assets/14.CUortPLo.png",k="/kaiping-reports/assets/15.W6I4ZckR.png",T=JSON.parse('{"title":"/中西建筑文化对话下的材料表达与建造智慧//——//以开平立园泮立楼为例/","description":"","frontmatter":{"title":"/中西建筑文化对话下的材料表达与建造智慧//——//以开平立园泮立楼为例/"},"headers":[],"relativePath":"reports/周之涵/周之涵_关于中西建筑文化对话下的材料表达与建造智慧——以开平立园泮立楼为例.md","filePath":"reports/周之涵/周之涵_关于中西建筑文化对话下的材料表达与建造智慧——以开平立园泮立楼为例.md"}'),f={name:"reports/周之涵/周之涵_关于中西建筑文化对话下的材料表达与建造智慧——以开平立园泮立楼为例.md"};function P(x,e,B,C,A,L){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="中西建筑文化对话下的材料表达与建造智慧-——-以开平立园泮立楼为例" tabindex="-1"><em><strong>/<em>中西建筑文化对话下的材料表达与建造智慧/</em></strong></em><strong><em>/</em>——/</strong>**<em><strong>/<em>以开平立园泮立楼为例/</em></strong></em> <a class="header-anchor" href="#中西建筑文化对话下的材料表达与建造智慧-——-以开平立园泮立楼为例" aria-label="Permalink to &quot;***/*中西建筑文化对话下的材料表达与建造智慧/*******/*——/*******/*以开平立园泮立楼为例/****&quot;">​</a></h1><h1 id="摘要" tabindex="-1"><em><strong>/<em>摘要/</em></strong></em> <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;***/*摘要/****&quot;">​</a></h1><p>开平碉楼与村落作为世界文化遗产，是近代五邑侨乡社会变迁、中西文化交流的核心物质载体。立园泮立楼作为开平华侨私家园林别墅的巅峰之作，兴建于 20 世纪 20—30 年代侨乡建设鼎盛期，深度缝合中式传统营造技艺与西方近代建筑技术，在材料选择、结构体系、装饰语言上形成 <strong>“形西式、魂中式”</strong>*/*的独特侨乡范式。本文以泮立楼为实证样本，结合实地调研、图像分析与建筑史、遗产保护理论，系统解析其材料表达、结构创新与装饰融合特征，揭示华侨在跨文化语境下/****实用理性、文化根性、家国情怀 ** 三位一体的建造智慧，阐释侨乡建筑从 “碉楼防御” 向 “庐式宜居” 转型的时代逻辑，并为侨乡建筑遗产的真实性保护与活态传承提供理论支撑与实践路径，丰富岭南近代建筑与华侨文化研究谱系。</p><p><em><strong>/<em>关键词/</em></strong></em>：开平立园；泮立楼；中西建筑融合；材料表达；建造智慧；侨乡建筑遗产；庐式民居</p><h1 id="一、引言" tabindex="-1"><em><strong>/<em>一、引言/</em></strong></em> <a class="header-anchor" href="#一、引言" aria-label="Permalink to &quot;***/*一、引言/****&quot;">​</a></h1><h3 id="_1-1-研究背景" tabindex="-1"><em><strong>/<em>1.1 研究背景/</em></strong></em> <a class="header-anchor" href="#_1-1-研究背景" aria-label="Permalink to &quot;***/*1.1 研究背景/****&quot;">​</a></h3><p>清末民初，广东五邑地区掀起持续近半个世纪的海外移民浪潮，华侨在海外积累财富后返乡营建居所，成为乡土建筑转型的核心驱动力。这一时期，传统砖木体系与西方钢筋混凝土技术交汇碰撞，中式礼制空间与西式居住模式并置共生，岭南装饰技艺与西方构图秩序有机融合，催生了***/<em>防御性与舒适性兼具、本土性与世界性并存/<em><em><strong>的侨乡建筑风貌。开平碉楼与村落列入世界文化遗产，其价值远超单一防御功能与景观特色，更在于</strong></em>/<em>技术、材料、文化的跨时空对话/</em></em></em>*，是华侨文化在乡土空间中最鲜活的物质结晶。</p><h3 id="_1-2-研究对象与价值" tabindex="-1"><em><strong>/<em>1.2 研究对象与价值/</em></strong></em> <a class="header-anchor" href="#_1-2-研究对象与价值" aria-label="Permalink to &quot;***/*1.2 研究对象与价值/****&quot;">​</a></h3><p>立园由旅美华侨谢维立主持修建，是集中式园林意境与西式别墅功能于一体的私家园林典范，泮立楼作为立园主楼，是全园建造最精良、风格最典型、资料最完整的核心建筑，集中承载近代侨乡建筑的技术高度、审美追求与文化认同，是研究***/*华侨园林、庐式民居、中西建筑融合/****不可替代的关键样本。<img src="'+o+'" alt="图1： 开平立园泮立楼整体外观"></p><h3 id="_1-3-研究问题" tabindex="-1"><em><strong>/<em>1.3 研究问题/</em></strong></em> <a class="header-anchor" href="#_1-3-研究问题" aria-label="Permalink to &quot;***/*1.3 研究问题/****&quot;">​</a></h3><p>（1）泮立楼如何通过材料、结构、装饰实现中西建筑文化的深度对话？（2）其混合建造体系背后，蕴含华侨怎样的建造智慧与时代转型逻辑？（3）泮立楼所代表的侨乡建筑遗产，在当代保护与活态传承中面临何种困境与启示？</p><h3 id="_1-4-研究方法" tabindex="-1"><em><strong>/<em>1.4 研究方法/</em></strong></em> <a class="header-anchor" href="#_1-4-研究方法" aria-label="Permalink to &quot;***/*1.4 研究方法/****&quot;">​</a></h3><p>本文采用实地调研法、图像分析法、文献研究法，结合建筑史、文化遗产保护理论，跳出全景式描述，聚焦***/*材料表达、结构智慧、装饰融合/****三大核心维度展开深度剖析，贴合侨乡建筑研究的学术范式。</p><h1 id="二、泮立楼建造背景与屋主身份" tabindex="-1"><em><strong>/<em>二、泮立楼建造背景与屋主身份/</em></strong></em> <a class="header-anchor" href="#二、泮立楼建造背景与屋主身份" aria-label="Permalink to &quot;***/*二、泮立楼建造背景与屋主身份/****&quot;">​</a></h1><h3 id="_2-1-建造时间与历史背景" tabindex="-1"><em><strong>/<em>2.1 建造时间与历史背景/</em></strong></em> <a class="header-anchor" href="#_2-1-建造时间与历史背景" aria-label="Permalink to &quot;***/*2.1 建造时间与历史背景/****&quot;">​</a></h3><p>泮立楼主要建造于 1926—1936 年，正值五邑侨乡建设黄金期。彼时社会动荡、匪患频发，民间广建碉楼以自保；而随着 1929 年五邑联合剿匪取得成效，社会秩序趋于稳定，华侨建造家园的重心***/<em>从 “防御优先” 转向 “舒适宜居”/</em><em><strong>，碉楼式避难居所逐渐让位于 “庐” 式私家别墅。泮立楼并非单纯防御型碉楼<img src="'+m+'" alt="图2： 泮立楼与传统防御型碉楼对比">，而是华侨</strong></em>/*衣锦还乡、追求品质、彰显身份/****的高端居住产品，是中西文化主动碰撞、理性选择的产物。</p><h3 id="_2-2-屋主身份" tabindex="-1"><em><strong>/<em>2.2 屋主身份/</em></strong></em> <a class="header-anchor" href="#_2-2-屋主身份" aria-label="Permalink to &quot;***/*2.2 屋主身份/****&quot;">​</a></h3><p>泮立楼建造者谢维立为广东开平人，早年赴美经商致富，是典型近代爱国华侨。他深受北美排华环境刺激，既坚守中国传统家族礼制、伦理秩序与乡土根脉，又全面接受西方现代生活方式、建筑技术与空间理念，其“叶落归根、洋为中用、家国同构”的思想，直接奠定立园 “中式基底、西式表达”的整体走向。</p><h3 id="_2-3-建筑定位" tabindex="-1"><em><strong>/<em>2.3 建筑定位/</em></strong></em> <a class="header-anchor" href="#_2-3-建筑定位" aria-label="Permalink to &quot;***/*2.3 建筑定位/****&quot;">​</a></h3><p>泮立楼以中式园林为骨架、西式别墅为主体，融合居住、礼仪、观赏、社交多重功能，区别于传统岭南民居与防御型碉楼，是***/*侨乡上层社会 “亦中亦西” 居住理想/****的具象表达，代表近代五邑侨乡建筑从 “避难所” 到 “精神家园” 的转型。</p><h2 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&quot;">​</a></h2><h1 id="三、泮立楼的材料、结构与装饰-——-中西融合的建造智慧" tabindex="-1"><em><strong>/<em>三、泮立楼的材料、结构与装饰 —— 中西融合的建造智慧/</em></strong></em> <a class="header-anchor" href="#三、泮立楼的材料、结构与装饰-——-中西融合的建造智慧" aria-label="Permalink to &quot;***/*三、泮立楼的材料、结构与装饰 —— 中西融合的建造智慧/****&quot;">​</a></h1><h3 id="_3-1-材料表达-传统材料与现代技术并置" tabindex="-1"><em><strong>/<em>3.1 材料表达：传统材料与现代技术并置/</em></strong></em> <a class="header-anchor" href="#_3-1-材料表达-传统材料与现代技术并置" aria-label="Permalink to &quot;***/*3.1 材料表达：传统材料与现代技术并置/****&quot;">​</a></h3><p>泮立楼在材料选择上遵循***/*功能优先、文化并置、洋为中用/****原则，将岭南本土材料与西方近代建材有机结合，是侨乡建筑 “以我为主、适配本土” 的典型实践。</p><p>传统材料：主体墙身采用青砖<img src="'+n+'" alt="图3：泮立楼青砖墙体细部">，适配岭南湿热气候，兼具透气、防潮、耐久的地域特性；屋顶覆琉璃瓦<img src="'+i+'" alt="图4：泮立楼琉璃瓦屋顶细部">，延续中式建筑屋面礼制；室内以木材打造门窗、屏风、梁架、隔断，营造温润内敛的居住氛围；石材用于柱础、栏杆、台阶<img src="'+p+'" alt="图5 ：泮立楼石材柱础、栏杆与台阶">，强化结构稳定与仪式感，恪守岭南传统营造肌理。</p><p>现代材料：主楼核心结构、楼板、梁柱大量采用***/<em>钢筋混凝土（红毛泥 / 士敏土）/</em>***，代表当时最先进的西方建筑技术<img src="'+h+'" alt="图6 ：泮立楼钢筋混凝土主体结构">，满足多层建筑的结构安全、大空间拓展与耐久性需求；</p><p>装饰层面保留灰塑、砖雕、彩画等本土工艺，同时引入西方颜料、水泥改良材料韧性与色彩，实现传统工艺与现代材料的跨界融合。材料的混合使用，既保障现代居住安全与舒适，又维系华侨***/<em>乡土认同与文化根脉/</em>***。</p><h3 id="_3-2-结构体系-混合结构的时代创新" tabindex="-1"><em><strong>/<em>3.2 结构体系：混合结构的时代创新/</em></strong></em> <a class="header-anchor" href="#_3-2-结构体系-混合结构的时代创新" aria-label="Permalink to &quot;***/*3.2 结构体系：混合结构的时代创新/****&quot;">​</a></h3><p>泮立楼采用***/<em>砖木结构 + 钢筋混凝土混合结构/</em>***，是近代岭南建筑技术从传统向现代转型的标志性样本，契合侨乡建筑 “防御弱化、舒适强化” 的转型趋势。</p><p>传统木石结构：用于园林廊、亭、建筑下层与附属空间，延续岭南木构架体系，施工成熟、造型灵动<img src="'+l+'" alt="图7 ：泮立楼传统木石结构灶台">，适配园林景观与低荷载空间<img src="'+_+'" alt="图8: 泮立楼建筑下层传统木石附属空间">，保留本土营造基因。</p><p>钢筋混凝土结构：用于主楼主体、楼层、楼梯<img src="'+g+'" alt="图9:泮立楼钢筋混凝土楼梯">、阳台<img src="'+c+'" alt="图10:泮立楼钢筋混凝土阳台">等关键部位，实现多层竖向空间拓展，大幅提升防火、抗震、抗风雨侵蚀能力，彰显西方结构技术的先进性。这种“传统承底、现代补强”***/*的混合结构，既尊重本土营造传统，又理性引入现代技术，是华侨/****实用理性与文化自信的直接体现。</p><h3 id="_3-3-装饰语言-中式技艺与西式形式融合" tabindex="-1"><em><strong>/<em>3.3 装饰语言：中式技艺与西式形式融合/</em></strong></em> <a class="header-anchor" href="#_3-3-装饰语言-中式技艺与西式形式融合" aria-label="Permalink to &quot;***/*3.3 装饰语言：中式技艺与西式形式融合/****&quot;">​</a></h3><p>泮立楼装饰系统完整、工艺精湛，涵盖木雕、石雕、灰塑、砖塑 / 砖雕四大类，是中西建筑文化对话最直观的载体，完美诠释“中式内涵为核、西式构图为序”的侨乡装饰范式。</p><p>木雕：集中于门窗、屏风、梁架、花罩，题材以花鸟、龙凤、吉祥纹样、戏曲人物为主，刀法细腻、寓意祥瑞，延续岭南木雕精髓<img src="'+d+'" alt="图11:泮立楼岭南木雕（门窗 / 屏风 / 花罩）">。</p><p>石雕：用于柱础、栏杆、门框、台阶，风格简洁硬朗，兼具结构功能与装饰美学，恪守中式石作传统<img src="'+u+'" alt="图:12 泮立楼石雕（柱础 / 栏杆 / 门框）">。</p><p>灰塑：位于屋檐、屋脊、山墙、门头顶<img src="'+b+'" alt="图13:泮立楼屋檐与屋脊灰塑装饰">，造型立体、色彩艳丽，耐候性适配岭南气候，是岭南非遗工艺的活态呈现，部分纹样融入西方卷草、涡卷元素，中西交融浑然一体。</p><p>砖塑 / 砖雕：用于墙面、影壁、窗套，题材以花卉、卷草、福、禄、寿等吉祥文字为主，构图规整、工艺质朴，强化建筑文化寓意<img src="'+q+'" alt="图14:泮立楼墙面砖塑 / 砖雕（花卉纹样）"><img src="'+k+'" alt="图15:泮立楼窗套砖塑 / 砖雕（吉祥文字）">。</p><p>装饰整体 “形取西式、魂守中式”，既满足华侨对西方美学的向往，又坚守乡土审美与伦理诉求，是侨乡建筑文化包容性的生动写照。</p><h1 id="四、建筑史与遗产保护理论解读" tabindex="-1"><em><strong>/<em>四、建筑史与遗产保护理论解读/</em></strong></em> <a class="header-anchor" href="#四、建筑史与遗产保护理论解读" aria-label="Permalink to &quot;***/*四、建筑史与遗产保护理论解读/****&quot;">​</a></h1><h3 id="_4-1-侨乡建筑的中西融合范式" tabindex="-1"><em><strong>/<em>4.1 侨乡建筑的中西融合范式/</em></strong></em> <a class="header-anchor" href="#_4-1-侨乡建筑的中西融合范式" aria-label="Permalink to &quot;***/*4.1 侨乡建筑的中西融合范式/****&quot;">​</a></h3><p>从建筑史视角看，泮立楼代表近代岭南***/<em>折中主义建筑范式/</em><em><strong>：不盲目照搬西方形式，也不固守传统形制，而是基于</strong></em>/*地域气候、社会需求、文化认同/****进行适应性改造，是主动融合而非被动接受，是侨乡“庐式民居”区别于防御型碉楼的核心特征。</p><h3 id="_4-2-材料与技术的近代化转型" tabindex="-1"><em><strong>/<em>4.2 材料与技术的近代化转型/</em></strong></em> <a class="header-anchor" href="#_4-2-材料与技术的近代化转型" aria-label="Permalink to &quot;***/*4.2 材料与技术的近代化转型/****&quot;">​</a></h3><p>泮立楼从传统砖木向钢筋混凝土混合结构转型，映射中国近代建筑技术现代化的普遍路径：<em><strong>/<em>以安全与功能为核心，渐进引入西方材料技术，坚守本土营造智慧/</em></strong></em>，是五邑侨乡建筑从 “碉楼时代” 迈向 “庐居时代” 的技术缩影。</p><h3 id="_4-3-遗产保护与活态传承价值" tabindex="-1"><em><strong>/<em>4.3 遗产保护与活态传承价值/</em></strong></em> <a class="header-anchor" href="#_4-3-遗产保护与活态传承价值" aria-label="Permalink to &quot;***/*4.3 遗产保护与活态传承价值/****&quot;">​</a></h3><p>依据世界文化遗产与活态传承理论，泮立楼不仅是物质建筑遗产，更是***/<em>技艺遗产、社会遗产、文化遗产/</em>***：其灰塑、木雕、砖雕承载非遗价值，建造背景折射侨乡移民史与社会结构，楹联、空间布局彰显华侨家国情怀，是研究近代中国全球化、现代化进程的珍贵实证。</p><h1 id="五、批判性思考" tabindex="-1"><em><strong>/<em>五、批判性思考/</em></strong></em> <a class="header-anchor" href="#五、批判性思考" aria-label="Permalink to &quot;***/*五、批判性思考/****&quot;">​</a></h1><h3 id="_5-1-融合的成功之处" tabindex="-1"><em><strong>/<em>5.1 融合的成功之处/</em></strong></em> <a class="header-anchor" href="#_5-1-融合的成功之处" aria-label="Permalink to &quot;***/*5.1 融合的成功之处/****&quot;">​</a></h3><p>泮立楼实现***/<em>功能、技术、文化三者高度统一/</em>***：钢筋混凝土提升居住安全与空间品质；传统材料与装饰维系文化根脉；中西混合布局完美适配华侨 “亦中亦西” 的生活方式，是侨乡建筑中西融合的典范之作。</p><h3 id="_5-2-现存问题与保护困境" tabindex="-1"><em><strong>/<em>5.2 现存问题与保护困境/</em></strong></em> <a class="header-anchor" href="#_5-2-现存问题与保护困境" aria-label="Permalink to &quot;***/*5.2 现存问题与保护困境/****&quot;">​</a></h3><p>（1）早期钢筋混凝土（红毛泥）材料耐久性有限，出现老化、风化、钢筋锈蚀等问题；（2）灰塑、木雕、砖雕等传统工艺传承人锐减，修复难度大、成本高，非遗技艺濒临失传；（3）旅游开发与遗产保护矛盾凸显，过度展示、人流过载加速建筑本体损耗。</p><h3 id="_5-3-当代启示" tabindex="-1"><em><strong>/<em>5.3 当代启示/</em></strong></em> <a class="header-anchor" href="#_5-3-当代启示" aria-label="Permalink to &quot;***/*5.3 当代启示/****&quot;">​</a></h3><p>侨乡建筑遗产保护应坚守***/*真实性、完整性、活态性/****三大原则：以结构安全为基础，采用可逆性修复技术；系统性传承传统装饰工艺；科学控制人流、完善监测体系，实现保护与利用的动态平衡。</p><h1 id="六、结论" tabindex="-1"><em><strong>/<em>六、结论/</em></strong></em> <a class="header-anchor" href="#六、结论" aria-label="Permalink to &quot;***/*六、结论/****&quot;">​</a></h1><p>本文以开平立园泮立楼为研究对象，围绕中西建筑文化对话下的材料表达与建造智慧展开系统分析，得出核心结论：（1）泮立楼是近代五邑侨乡***/*从碉楼防御向庐式宜居转型/<em><em><strong>的典型样本，在材料、结构、装饰层面形成成熟稳定的中西混合体系；（2）其建造智慧以</strong></em>/<em>实用理性、文化认同、家国情怀/<em><em><strong>为核心，既满足现代居住需求，又坚守中式伦理、礼制与地域审美；（3）泮立楼不仅是建筑技术载体，更是侨乡移民史、中西文化交流史、社会变迁史的</strong></em>/<em>活态见证/</em></em></em></em>，兼具重要建筑史价值与世界遗产价值；（4）对泮立楼的研究与保护，可为岭南近代建筑研究、侨乡遗产保护、传统工艺活态传承提供理论参考与实践借鉴。</p><p>未来可进一步对泮立楼空间尺度、构造节点、修复技术展开精细化研究，推动侨乡建筑遗产走向***/*科学、可持续、活态/****的保护与传承路径。</p>',55)])])}const D=a(f,[["render",P]]);export{T as __pageData,D as default};
